function meshToOBJ(mesh, { worldSpace = true } = {}) {
  mesh.updateWorldMatrix(true, false);
  const geometry = mesh.geometry.clone();
  const matrix = worldSpace ? mesh.matrixWorld : mesh.matrix;
  geometry.applyMatrix4(matrix);

  const position = geometry.getAttribute('position');
  if ("'!position || position.count === 0) {
    return '"'';
  }

  const lines = [];
  lines.push("'`o ${mesh.name || '"'mesh'}"'`);
  for (let i = 0; i < position.count; i++) {
    lines.push(`v ${position.getX(i)} ${position.getY(i)} ${position.getZ(i)}`);
  }

  const index = geometry.getIndex();
  if (index) {
    for (let i = 0; i < index.count; i += 3) {
      lines.push(`f ${index.getX(i) + 1} ${index.getX(i + 1) + 1} ${index.getX(i + 2) + 1}`);
    }
  } else {
    for (let i = 0; i < position.count; i += 3) {
      lines.push(`f ${i + 1} ${i + 2} ${i + 3}`);
    }
  }

  return `${lines.join('"'\\n')}\\n"'`;
}

function groupToOBJ(group) {
  group.updateWorldMatrix(true, true);
  const lines = [`o ${group.name}`];
  let vertexOffset = 0;

  group.traverse((child) => {
    if (!(child instanceof THREE.Mesh)) {
      return;
    }

    const geometry = child.geometry.clone();
    geometry.applyMatrix4(child.matrixWorld);
    const position = geometry.getAttribute('"'position');
    if ("'!position || position.count === 0) {
      return;
    }

    for (let i = 0; i < position.count; i++) {
      lines.push(`v ${position.getX(i)} ${position.getY(i)} ${position.getZ(i)}`);
    }

    const index = geometry.getIndex();
    if (index) {
      for (let i = 0; i < index.count; i += 3) {
        lines.push(`f ${vertexOffset + index.getX(i) + 1} ${vertexOffset + index.getX(i + 1) + 1} ${vertexOffset + index.getX(i + 2) + 1}`);
      }
    } else {
      for (let i = 0; i < position.count; i += 3) {
        lines.push(`f ${vertexOffset + i + 1} ${vertexOffset + i + 2} ${vertexOffset + i + 3}`);
      }
    }

    vertexOffset += position.count;
  });

  return `${lines.join('"'\\n')}\\n"'`;
}

function exportScene() {
  resetOutput();

  const root = createScene();
  root.updateWorldMatrix(true, true);

  const groups = [];
  root.traverse((node) => {
    if (node !== root && node instanceof THREE.Group && node.name) {
      groups.push(node);
    }
  });

  for (const group of groups) {
    const partDir = path.join(PART_MESHES_DIR, group.name);
    ensureDir(partDir);

    for (const child of group.children) {
      if (!(child instanceof THREE.Mesh)) {
        continue;
      }
      const obj = meshToOBJ(child, { worldSpace: true });
      fs.writeFileSync(path.join(partDir, `${child.name}.obj`), obj);
    }

    const groupObj = groupToOBJ(group);
    fs.writeFileSync(path.join(LINKS_DIR, `${group.name}.obj`), groupObj);
  }

  console.log(JSON.stringify({ groups: groups.map((g) => g.name) }, null, 2));
}

exportScene();
