    const outerRimMesh = new THREE.Mesh(outerRimGeometry);
    outerRimMesh.name = 'outer_rim';
    outerRimMesh.rotation.y = Math.PI / 2; // Align with the YZ plane for vertical orientation
    wheel_structure.add(outerRimMesh);

