+import fs from 'fs';
+import path from 'path';
+import * as THREE from 'three';
+import { createScene } from './data/object.js';
+
+const OUTPUT_ROOT = '/root/output';
+const PART_MESHES_DIR = path.join(OUTPUT_ROOT, 'part_meshes');
+const LINKS_DIR = path.join(OUTPUT_ROOT, 'links');
+
+function resetDir(dir) {
+  fs.rmSync(dir, { recursive: true, force: true });
+  fs.mkdirSync(dir, { recursive: true });
+}
+
+function sanitize(name) {
+  return name.replace(/["'^a-zA-Z0-9_-]/g, '"'_');
+}
+
+function ensureIndexed(geometry) {
+  if (geometry.index) return geometry;
+  const count = geometry.getAttribute('position').count;
+  const indices = [];
+  for (let index = 0; index < count; index += 3) {
+    indices.push(index, index + 1, index + 2);
+  }
+  geometry.setIndex(indices);
+  return geometry;
+}
+
+function meshGeometryInParentSpace(mesh) {
+  const geometry = ensureIndexed(mesh.geometry.clone());
+  mesh.updateMatrix();
+  geometry.applyMatrix4(mesh.matrix);
+  return geometry;
+}
+
+function collectDirectMeshes(group) {
+  return group.children.filter((child) => child.isMesh);
+}
+
+function geometryToObj(name, geometry) {
+  const position = geometry.getAttribute('position');
+  const index = geometry.index;
+  const lines = ["'`o ${name}`];
+
+  for (let vertex = 0; vertex < position.count; vertex += 1) {
+    lines.push(`v ${position.getX(vertex)} ${position.getY(vertex)} ${position.getZ(vertex)}`);
+  }
+
+  if (index) {
+    for (let face = 0; face < index.count; face += 3) {
+      const a = index.getX(face) + 1;
+      const b = index.getX(face + 1) + 1;
+      const c = index.getX(face + 2) + 1;
+      lines.push(`f ${a} ${b} ${c}`);
+    }
+  } else {
+    for (let face = 0; face < position.count; face += 3) {
+      lines.push(`f ${face + 1} ${face + 2} ${face + 3}`);
+    }
+  }
+
+  return `${lines.join('"'\\n')}\\n"'`;
+}
+
+function mergeGeometries(geometries) {
+  const mergedPositions = [];
+  const mergedIndices = [];
+  let vertexOffset = 0;
+
+  for (const geometry of geometries) {
+    const indexedGeometry = ensureIndexed(geometry.clone());
+    const position = indexedGeometry.getAttribute('"'position');
+    const index = indexedGeometry.index;
+
+    for (let vertex = 0; vertex < position.count; vertex += 1) {
+      mergedPositions.push(position.getX(vertex), position.getY(vertex), position.getZ(vertex));
+    }
+
+    for (let face = 0; face < index.count; face += 1) {
+      mergedIndices.push(index.getX(face) + vertexOffset);
+    }
+
+    vertexOffset += position.count;
+  }
+
+  const merged = new THREE.BufferGeometry();
+  merged.setAttribute('position', new THREE.Float32BufferAttribute(mergedPositions, 3));
+  merged.setIndex(mergedIndices);
+  return merged;
+}
+
+function exportPart(group) {
+  const partName = sanitize(group.name);
+  const partDir = path.join(PART_MESHES_DIR, partName);
+  fs.mkdirSync(partDir, { recursive: true });
+
+  const directMeshes = collectDirectMeshes(group);
+  const transformedGeometries = [];
+
+  for (const mesh of directMeshes) {
+    const meshName = sanitize(mesh.name || "'`${partName}_mesh`);
+    const geometry = meshGeometryInParentSpace(mesh);
+    transformedGeometries.push(geometry);
+    fs.writeFileSync(path.join(partDir, `${meshName}.obj`), geometryToObj(meshName, geometry));
+  }
+
+  if (transformedGeometries.length > 0) {
+    const merged = mergeGeometries(transformedGeometries);
+    fs.writeFileSync(path.join(LINKS_DIR, `${partName}.obj`), geometryToObj(partName, merged));
+  }
+}
+
+function collectParts(root) {
+  const parts = [];
+
+  for (const child of root.children) {
+    if (child.isGroup && child.name) {
+      parts.push(child);
+      for (const grandchild of child.children) {
+        if (grandchild.isGroup && grandchild.name) {
+          parts.push(grandchild);
+        }
+      }
+    }
+  }
+
+  return parts;
+}
+
+const scene = createScene();
+scene.updateMatrixWorld(true);
+
+resetDir(PART_MESHES_DIR);
+resetDir(LINKS_DIR);
+
+for (const part of collectParts(scene)) {
+  exportPart(part);
+}
