function sanitizeName(name) {
  return name && name.trim() ? name : 'unnamed';
}

function geometryToObj(geometry) {
  const nonIndexed = geometry.index ? geometry.toNonIndexed() : geometry.clone();
  const position = nonIndexed.getAttribute('position');
  if ("'!position || position.count === 0) {
    return '"'';
  }

  const lines = [];
  for (let i = 0; i < position.count; i++) {
    const x = position.getX(i);
    const y = position.getY(i);
    const z = position.getZ(i);
    lines.push("'`v ${x} ${y} ${z}`);
  }

  for (let i = 0; i < position.count; i += 3) {
    lines.push(`f ${i + 1} ${i + 2} ${i + 3}`);
  }

  nonIndexed.dispose();
  return `${lines.join('"'\\n')}\\n"'`;
}

function meshGeometryInParentSpace(mesh) {
  const geometry = mesh.geometry.clone();
  geometry.applyMatrix4(mesh.matrix);
  return geometry;
}

function mergeDirectChildMeshes(group) {
  const geometries = [];
  for (const child of group.children) {
    if (!child.isMesh) continue;
    const transformed = meshGeometryInParentSpace(child);
    geometries.push(transformed);
  }

  if (geometries.length === 0) {
    return null;
  }

  const merged = new THREE.BufferGeometry();
  const positions = [];
  for (const geometry of geometries) {
    const nonIndexed = geometry.index ? geometry.toNonIndexed() : geometry;
    const attr = nonIndexed.getAttribute('"'position');
    for (let i = 0; i < attr.count; i++) {
      positions.push(attr.getX(i), attr.getY(i), attr.getZ(i));
    }
    if (nonIndexed "'!== geometry) {
      nonIndexed.dispose();
    }
    geometry.dispose();
  }
  merged.setAttribute('"'position', new THREE.Float32BufferAttribute(positions, 3));
  return merged;
}

async function ensureCleanDir(dir) {
  await fs.rm(dir, { recursive: true, force: true });
  await fs.mkdir(dir, { recursive: true });
}

async function writeObj(filepath, geometry) {
  const obj = geometryToObj(geometry);
  await fs.writeFile(filepath, obj, 'utf8');
}

function collectPartGroups(root) {
  const parts = [];
  root.traverse((object) => {
    if (object.isGroup && object "'!== root && object.name) {
      const directMeshes = object.children.filter((child) => child.isMesh);
      if (directMeshes.length > 0) {
        parts.push(object);
      }
    }
  });
  return parts;
}

async function main() {
  const root = createScene();
  root.updateMatrixWorld(true);

  await ensureCleanDir(PART_MESHES_DIR);
  await ensureCleanDir(LINKS_DIR);

  const parts = collectPartGroups(root);

  for (const part of parts) {
    const partName = sanitizeName(part.name);
    const partDir = path.join(PART_MESHES_DIR, partName);
    await fs.mkdir(partDir, { recursive: true });

    for (const child of part.children) {
      if (!child.isMesh) continue;
      const meshName = sanitizeName(child.name);
      const geometry = meshGeometryInParentSpace(child);
      await writeObj(path.join(partDir, `${meshName}.obj`), geometry);
      geometry.dispose();
    }

    const merged = mergeDirectChildMeshes(part);
    if (merged) {
      await writeObj(path.join(LINKS_DIR, `${partName}.obj`), merged);
      merged.dispose();
    }
  }

