/bin/bash -lc "node - <<'NODE'
import { createScene } from '/root/data/object.js';
const root = createScene();
function walk(node, depth=0){
  const indent=' '.repeat(depth*2);
  console.log("'`${indent}${node.type} ${node.name||'"'(unnamed)'} children="'${node.children?.length||0}`);
  for(const ch of node.children||[]) walk(ch, depth+1);
}
walk(root);
NODE'
sed -n '1,320p' /root/export_parts.mjs 2>/dev/null || true
ls -la /root && printf '\\n--- existing output ---\\n' && find /root/output -maxdepth 3 -type f | sort 2>/dev/null || true && printf '\\n--- export_parts.mjs ---\\n' && cat /root/export_parts.mjs 2>/dev/null || true
node /root/export_parts.mjs && find /root/output -maxdepth 3 -type f | sort | sed -n '1,200p'
